template-STD_LIST.scripts:
			function LoadList(force)
{
  var proxy=GetProxy(); //as NomadProxy
  var param=new NomadXML("DATA");
  var lst=Ctrl("LIST");

  var max=CFG.GetAttrInt("maxreg");
  if (isNaN(max)) max=0;

  if (force || Ctrl("VALUES").GetXValue()=="*" || Ctrl("VALUES").GetXValue()=="" )
  {
  param.SetAttr("parent" ,Ctrl("PARENT").GetXValue());
  param.SetAttr("order"  ,Ctrl("ORDER").GetXValue().substr(1));
  param.SetAttr("asc"    ,Ctrl("ORDER").GetXValue().substr(0,1)=="+"?"1":"0");
  if (Ctrl("BUSCAR")) 
  	if (isNaN(Ctrl("BUSCAR").GetXValue())) param.SetAttr("stringSearch" ,Ctrl("BUSCAR").GetXValue());
  	else param.SetAttr("numberSearch" ,Ctrl("BUSCAR").GetXValue());
  if (max>0) param.SetAttr("LEN",max);

  //Agrego los Parametros Adicionales
  for (cur=CFG.FirstChild(); cur!=null; cur=cur.Next())
  {
  	if (Ctrl(cur.GetAttr("name")))
  		param.SetAttr(cur.GetAttr("name"), Ctrl(cur.GetAttr("name")).GetXValue());

	//Faltan algunos Parametros  		
  	if (cur.GetAttrBool("req") && Ctrl(cur.GetAttr("name")).GetXValue()=="")
  	{
	  Ctrl("VALUES").SetXValue("");
	  Ctrl("LIST_REG").SetXValue("Especifique algún criterio de búsqueda.");

		//Limpio todo
	  lst.IDs=new Array();
	  lst.SetXValue("");          

		//Mensaje Inicial de la Lista
		lst.MsgEmply="Especifique algún criterio de búsqueda...";
		lst.ResetSQL();
  		return;
  	}
  }

  //Cargo el RS
  if(CFG.GetAttr("METHOD")!="")
  {
    var ca=proxy.RPCService();
    ca.AddParam(new NomadRPCParamOut("OUT", "Nomad.NSystem.Object", "Nomad.NSystem.Proxy.NomadXML"));

    //Lista de Parametros
    var p=0;
    var mecfg=new NomadXML(Ctrl("main").getResource("QRY_IDS_METHOD"));
    for (cur=mecfg.FirstChild(); cur!=null; cur=cur.Next())
    {
      switch(cur.GetAttr("value").split(":")[0])
      {
        case "ctrl":
          p++;
          ca.AddParam(new NomadRPCParam("P"+p, "IN", Ctrl(cur.GetAttr("value").substr(5)).GetXValue(), "String"));
          break;
        case "const":
          p++;
          ca.AddParam(new NomadRPCParam("P"+p, "IN", cur.GetAttr("value").substr(6), "String"));
          break;
        default:
          if (cur.GetAttr("value")!="")
          {
            p++;
            ca.AddParam(new NomadRPCParam("P"+p, "IN", cur.GetAttr("value"), "String"));
          }
          break;
      }
    }

    ca.Execute(CFG.GetAttr("METHOD").split(":")[0],CFG.GetAttr("METHOD").split(":")[1]);
    RS=new NomadXML(ca.GetParam("OUT").Data);
  } else
  {
    RS=proxy.SQLService().GetXML(Ctrl("main").getResource("QRY_IDS"), param.ToString());
  }

  //Actualizo el Label
  var total=RS.GetAttrInt("total"); if (isNaN(total)) total=0;
  var count=RS.GetAttrInt("count"); if (isNaN(count)) count=0;


//Limpio la Lista
  lst.IDs=new Array();

  //Genero la Lista de IDS                                
  var found=false;
  for (var cur=RS.FirstChild(); cur!=null; cur=cur.Next())
  	if (max==0 || lst.IDs.length<max)
  	{
    	lst.IDs.push(cur.GetAttr("id"));
    	if (cur.GetAttr("id")==lst.GetXValue()) found=true;
    }

  Ctrl("VALUES").SetXValue(lst.IDs.length>100 ? "*" : lst.IDs.join("|"))
  } else
  {
//Cargo la Lista
  lst.IDs=Ctrl("VALUES").GetXValue().split("|");
  count=lst.IDs.length
  }

  if (max>0 && count>=max)
  {                      
  	if (count==max)
  		Ctrl("LIST_REG").SetXValue("Primeros "+max+" registros");
  	else                                                      
  		Ctrl("LIST_REG").SetXValue("ERROR AL MOSTRAR LA CANTIDAD DE REGISTROS ("+max+"!="+count+")");
  } else            
  if (count==0)
  {
  	Ctrl("LIST_REG").SetXValue("No hay registros");
  } else
  {
  	Ctrl("LIST_REG").SetXValue(count + " registros");
  }


  lst.MsgEmply="No hay registros";
  if (!found) lst.SetXValue("");
  lst.ResetSQL();
}

template-STD_REG.scripts:
			function controlMayor(me)
{
	if(parseInt(Ctrl('e_lsd_inicial').GetCValue())>=parseInt(Ctrl('e_lsd_final').GetCValue()))
	{ 
		if(me.m_ID=='e_lsd_final')
		{
			alert("El código LSD final debe ser mayor al inicial");
			Ctrl('e_lsd_final').SetCValue("");

		}
		else
		{ 
			alert("El código LSD inicial debe ser menor al final");
			Ctrl('e_lsd_inicial').SetCValue("");
		}
	}
}
